(482, 482, 'vi', 'Intel NUC 13 Pro', '', '<p>Intel NUC 13 Pro là hệ thống máy tính để bàn Intel mạnh mẽ, được tối ưu hóa cho công việc và giải trí chuyên nghiệp. Trang bị linh kiện tiên tiến, khả năng nâng cấp linh hoạt và độ bền cao.</p>', '2024-05-14 05:29:00', '2024-05-14 05:29:00'),
(483, 483, 'vi', 'Fujitsu ESPRIMO D7012', '', '<p>Fujitsu ESPRIMO D7012 là hệ thống máy tính để bàn Fujitsu mạnh mẽ, được tối ưu hóa cho công việc và giải trí chuyên nghiệp. Trang bị linh kiện tiên tiến, khả năng nâng cấp linh hoạt và độ bền cao.</p>', '2024-05-14 05:29:00', '2024-05-14 05:29:00'),
(484, 484, 'vi', 'Huawei MateStation S', '', '<p>Huawei MateStation S là hệ thống máy tính để bàn Huawei mạnh mẽ, được tối ưu hóa cho công việc và giải trí chuyên nghiệp. Trang bị linh kiện tiên tiến, khả năng nâng cấp linh hoạt và độ bền cao.</p>', '2024-05-14 05:29:00', '2024-05-14 05:29:00'),
(485, 485, 'vi', 'Samsung All-in-One Pro', '', '<p>Samsung All-in-One Pro là hệ thống máy tính để bàn Samsung mạnh mẽ, được tối ưu hóa cho công việc và giải trí chuyên nghiệp. Trang bị linh kiện tiên tiến, khả năng nâng cấp linh hoạt và độ bền cao.</p>', '2024-05-14 05:29:00', '2024-05-14 05:29:00');
